// Claude Code icon - Anthropic's Claude logo (simplified burst/star design)
export function ClaudeCodeIcon({ className }: AgentIconProps) {
  return (
    <svg
      viewBox="0 0 24 24"
      fill="none"
      xmlns="http://www.w3.org/2000/svg"
      className={cn("h-4 w-4", className)}
    >
      {/* Claude's signature burst/starburst design */}
      <path
        d="M12 2L13.09 8.26L18 4L14.74 9.91L21 10L14.74 12.09L18 18L13.09 14.74L12 21L10.91 14.74L6 18L9.26 12.09L3 10L9.26 9.91L6 4L10.91 8.26L12 2Z"
        fill="currentColor"
        fillOpacity="0.9"
      />
    </svg>
  )
}

