// OpenCode icon - Open source code symbol (brackets with sparkle/open concept)
export function OpenCodeIcon({ className }: AgentIconProps) {
  return (
    <svg
      viewBox="0 0 24 24"
      fill="none"
      xmlns="http://www.w3.org/2000/svg"
      className={cn("h-4 w-4", className)}
    >
      {/* Code brackets representing open-source coding */}
      <path
        d="M8 3L3 12L8 21"
        stroke="currentColor"
        strokeWidth="2"
        strokeLinecap="round"
        strokeLinejoin="round"
      />
      <path
        d="M16 3L21 12L16 21"
        stroke="currentColor"
        strokeWidth="2"
        strokeLinecap="round"
        strokeLinejoin="round"
      />
      {/* Center dot representing the "open" concept */}
      <circle cx="12" cy="12" r="2" fill="currentColor" />
    </svg>
  )
}

// Helper function to get the icon component for an agent
export function AgentIcon({ agent, className }: { agent: Agent; className?: string }) {
  switch (agent) {
    case "claude-code":
      return <ClaudeCodeIcon className={className} />
    case "codex":
      return <CodexIcon className={className} />
    case "opencode":
      return <OpenCodeIcon className={className} />
    default:
      return <ClaudeCodeIcon className={className} />
  }
}
